// In app/common/newdomain.go
func NewMyDomainService(
    creditsConfig config.CreditsConfiguration,
    ledgerService ledger.Ledger,
    db *entdb.Client,
) (mydomain.Service, error) {
    if !creditsConfig.Enabled {
        return mydomainnoop.NewService(), nil
    }
    adapter, err := mydomainadapter.New(mydomainadapter.Config{Client: db})
    if err != nil {
        return nil, fmt.Errorf("init mydomain adapter: %w", err)
    }
    return mydomainservice.New(mydomainservice.Config{
        Adapter: adapter,
        Ledger:  ledgerService,
    })
}

// app/config/newdomain.go
type NewDomainConfiguration struct {
    Enabled  bool
    Endpoint string
}

func (c NewDomainConfiguration) Validate() error {
    var errs []error
    if c.Enabled && c.Endpoint == "" {
        errs = append(errs, errors.New("endpoint is required when enabled"))
    }
    return errors.Join(errs...)
}

func ConfigureNewDomain(v *viper.Viper) {
    v.SetDefault("newdomain.enabled", false)
    v.SetDefault("newdomain.endpoint", "")
}

